import{_ as t,o,c as i,a0 as a}from"./chunks/framework.DvNw9GNH.js";const h=JSON.parse('{"title":"🛰️ Bunti Box Model","description":"","frontmatter":{},"headers":[],"relativePath":"layout.md","filePath":"layout.md"}'),n={name:"layout.md"};function r(l,e,d,c,s,g){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="🛰️-bunti-box-model" tabindex="-1">🛰️ Bunti Box Model <a class="header-anchor" href="#🛰️-bunti-box-model" aria-label="Permalink to &quot;🛰️ Bunti Box Model&quot;">​</a></h1><p>Bunti features a zero-dependency, mathematically absolute layout engine designed specifically for terminal environments. It guarantees 100% precision in width, padding, and border alignment, preventing the &quot;Jagged Border&quot; artifacts common in traditional TUI libraries.</p><hr><h2 id="📐-sizing-constraints" tabindex="-1">📐 Sizing &amp; Constraints <a class="header-anchor" href="#📐-sizing-constraints" aria-label="Permalink to &quot;📐 Sizing &amp; Constraints&quot;">​</a></h2><ul><li><strong>Zero-Default Ghost Boxes</strong>: By default, <code>box()</code> applies no borders and no padding (<code>[0,0]</code>), collapsing tightly around its content to serve as invisible structural wrappers.</li><li><strong>Absolute Sizing</strong>: Exact character column/row dimensions (e.g., <code>width: 30</code>, <code>height: 10</code>).</li><li><strong>Relative Sizing</strong>: Percentage-based width relative to the parent container (e.g., <code>width: &#39;90%&#39;</code>).</li><li><strong>Flex Sizing</strong>: Fluid layouts using fractional units (e.g., <code>width: &#39;1fr&#39;</code>).</li><li><strong>Clamped Constraints</strong>: Support for <code>minWidth</code>, <code>maxWidth</code>, <code>minHeight</code>, and <code>maxHeight</code> to prevent layout collapse or overflow.</li></ul><h2 id="🧭-multi-axis-alignment-positioning" tabindex="-1">🧭 Multi-Axis Alignment &amp; Positioning <a class="header-anchor" href="#🧭-multi-axis-alignment-positioning" aria-label="Permalink to &quot;🧭 Multi-Axis Alignment &amp; Positioning&quot;">​</a></h2><ul><li><strong>Anchored Positioning</strong>: Snap top-level components to absolute terminal edges (<code>anchor: &#39;top&#39;</code>, <code>anchor: &#39;bottom&#39;</code>).</li><li><strong>Horizontal Alignment (<code>align</code>)</strong>: Strict per-line formatting for <code>left</code>, <code>center</code>, and <code>right</code> text flow within constraints.</li><li><strong>Vertical Alignment (<code>valign</code>)</strong>: Precise distribution of whitespace for <code>top</code>, <code>middle</code>, and <code>bottom</code> placement of content blocks (supports both single-line and multi-line content).</li><li><strong>Symmetrical Padding</strong>: Predictable <code>[vertical, horizontal]</code> padding that integrates seamlessly with constraint math.</li></ul><h2 id="📝-typography-flow" tabindex="-1">📝 Typography &amp; Flow <a class="header-anchor" href="#📝-typography-flow" aria-label="Permalink to &quot;📝 Typography &amp; Flow&quot;">​</a></h2><ul><li><strong>Surgical Wrapping</strong>: Word-based text flow that automatically folds content at constraint boundaries to prevent TTY artifacts, with a fallback to character-breaking for over-width tokens.</li><li><strong>ANSI-Aware Truncation</strong>: Safe <code>truncate(str, width)</code> utility that mathematically splices strings without corrupting embedded ANSI color codes or escape sequences.</li><li><strong>Deep-Integrated Nerd-Emoji Swap</strong>: A global interceptor that safely swaps raw emojis (e.g., <code>🛰️</code>, <code>🌀</code>) for Width-1 Nerd Font tactical signals (<code></code>, <code>󰁥</code>) <em>before</em> any layout math occurs, guaranteeing 100% border stability.</li></ul><h2 id="🧱-structural-primitives" tabindex="-1">🧱 Structural Primitives <a class="header-anchor" href="#🧱-structural-primitives" aria-label="Permalink to &quot;🧱 Structural Primitives&quot;">​</a></h2><ul><li><strong>Industrial Borders</strong>: Opinionated, high-fidelity border sets (<code>default</code>, <code>rounded</code>, <code>double</code>, <code>dashed</code>, <code>dotted</code>, <code>frame</code>, <code>thick-frame</code>, <code>classic</code>).</li><li><strong>Side-Specific Colors</strong>: Independent 24-bit color assignment for Top, Bottom, Left, and Right borders, enabling native UI depth and relative contrast shading.</li><li><strong>Tabular Data (<code>table()</code>)</strong>: Rigid, perfectly aligned column-first grid structures with shared gutters and explicit column widths/alignments.</li></ul><h2 id="🎨-visual-depth" tabindex="-1">🎨 Visual Depth <a class="header-anchor" href="#🎨-visual-depth" aria-label="Permalink to &quot;🎨 Visual Depth&quot;">​</a></h2><ul><li><strong>24-Bit TrueColor</strong>: Full RGB hex support integrated directly into the <code>fg</code> and <code>bg</code> rendering pipeline.</li><li><strong>Dynamic Gradients</strong>: Multi-stop interpolation (<code>midnight</code> -&gt; <code>bunti-blue</code> -&gt; <code>ocean</code>) capable of painting horizontally or vertically across structural nodes.</li><li><strong>Relative Contrast</strong>: Built-in <code>lighten()</code> and <code>darken()</code> mathematics to automatically calculate border shades relative to background fills.</li></ul>',13)])])}const p=t(n,[["render",r]]);export{h as __pageData,p as default};
